    Example:
    get_closest_vowel("yogurt") ==> "u"
    get_closest_vowel("FULL") ==> "U"
    get_closest_vowel("quick") ==> ""
    get_closest_vowel("ab") ==> ""
    """

    # Solution 1: O(n)
    for i in range(1, len(word)):
        # Check if it is vowel
        if (word[i].upper() in "AEIOU") and (word[i - 1].upper() not in "AEIOU"):
            return word[i].upper()

    # Solution 2: O(n)
    for i in range(1, len(word)):
        # Check if it is vowel
        if (word[len(word) - i].upper() in "AEIOU") and (word[len(word) - i - 1].upper() not in "AEIOU"):
            return word[len(word) - i].upper()

    return ""

